input.command:
cd "d:/ClaudeWorkspace/08_客户跟进/Okki" && node -e "
const fs = require('fs');
const raw = JSON.parse(fs.readFileSync('data/tm_conversations_full.json', 'utf-8'));
const data = raw.conversations;
console.log('Total:', raw.total, '| Exported:', raw.exportedAt);
console.log('Conversations:', data.length);

const unread = data.filter(d => (d.unreadCount || 0) > 0).length;
console.log('Unread:', unread);

// Count with real non-system messages
const withMsg = data.filter(d => {
  const c = (d.latestMessage || {}).content || '';
  return c && !c.includes('自动接待') && !c.includes('Marco大模型翻译') && !c.includes('流失风险') && !c.includes('AI给您生成') && !c.includes('visitor');
}).length;
console.log('With real latestMessage:', withMsg);

const sorted = [...data].sort((a,b) => (b.lastContactTime || 0) - (a.lastContactTime || 0));
console.log('\n=== TOP 20 MOST RECENT ===');
sorted.slice(0,20).forEach(d => {
  const ts = d.lastContactTime ? new Date(d.lastContactTime).toISOString().slice(0,16).replace('T',' ') : 'N/A';
  const name = (d.customerName || '?').slice(0,35);
  const unread = d.unreadCount || 0;
  const lm = (d.latestMessage || {}).content || '';
  const direction = (d.latestMessage || {}).direction || '';
  const lmClean = lm.replace(/\n/g,' ').slice(0,90);
  const dir = direction === 'received' ? '←客' : direction === 'send' ? '我→' : '?';
  console.log(ts + ' | ' + dir + ' | unread:' + unread + ' | ' + name + ' | ' + lmClean);
});

// Count by recency buckets
const now = Date.now();
const last24h = sorted.filter(d => (d.lastContactTime || 0) > now - 86400000).length;
const last3d = sorted.filter(d => (d.lastContactTime || 0) > now - 3*86400000).length;
const last7d = sorted.filter(d => (d.lastContactTime || 0) > now - 7*86400000).length;
console.log('\n=== RECENCY ===');
console.log('Last 24h:', last24h);
console.log('Last 3d:', last3d);
console.log('Last 7d:', last7d);

// Count by contact day
const byDay = {};
sorted.forEach(d => {
  const day = d.lastContactTime ? new Date(d.lastContactTime).toISOString().slice(0,10) : 'unknown';
  byDay[day] = (byDay[day] || 0) + 1;
});
console.log('\n=== BY DAY ===');
Object.entries(byDay).sort().forEach(([day,count]) => console.log(day + ': ' + count + ' conversations'));
"

