cd "d:/ClaudeWorkspace/08_客户跟进/Okki" && node -e "
const fs = require('fs');
const raw = JSON.parse(fs.readFileSync('data/tm_conversations_full.json', 'utf-8'));
const data = raw.conversations;

// Show all May 5 conversations with real detail
const may5 = data.filter(d => {
  if (!d.lastContactTime) return false;
  const dt = new Date(d.lastContactTime);
  return dt.getUTCDate() === 5 && dt.getUTCMonth() === 4 && dt.getUTCFullYear() === 2026;
}).sort((a,b) => b.lastContactTime - a.lastContactTime);

console.log('=== MAY 5 CONVERSATIONS (' + may5.length + ' total) ===\n');
may5.forEach((d, i) => {
  const ts = new Date(d.lastContactTime).toISOString().slice(0,19).replace('T',' ');
  const name = d.name || d.companyName || '?';
  const country = d.country || '?';
  const msgType = (d.latestMessage || {}).messageType || '?';
  const contactRead = (d.latestMessage || {}).contactRead;
  const content = ((d.latestMessage || {}).content || '').replace(/\n/g,' ').slice(0,100);
  const dir = msgType === 'received' ? '←客' : msgType === 'send' ? '我→' : '?';
  const readStatus = msgType === 'send' ? (contactRead ? '[已读]' : '[未读]') : '';
  console.log((i+1) + '. ' + ts + ' ' + dir + ' ' + readStatus);
  console.log('   ' + name + ' | ' + country + ' | Lv:' + (d.level || '?'));
  console.log('   ' + content);
  console.log('   cid: ' + d.cid);
  console.log();
});
"

