/**
 * OKKI 快速同步 — 自动化抓取最新会话元数据
 *
 * 使用：
 * 1. 关闭 Chrome
 * 2. node scripts/quick_sync.js
 * 3. 自动打开 OKKI → 拦截 API → 保存 → 退出（~15秒）
 */

const { chromium } = require('playwright');
const path = require('path');
const fs = require('fs');

const PROFILE_PATH = 'C:\\Users\\Administrator\\AppData\\Local\\Google\\Chrome\\User Data\\Profile 4';
const OUTPUT_DIR = path.join(__dirname, '..', 'data');

if (!fs.existsSync(OUTPUT_DIR)) {
  fs.mkdirSync(OUTPUT_DIR, { recursive: true });
}

const captured = [];

async function main() {
  console.log('[QuickSync] 启动 Chrome (Profile 4)...');

  const browser = await chromium.launchPersistentContext(PROFILE_PATH, {
    channel: 'chrome',
    headless: false,
    viewport: { width: 1440, height: 900 },
  });

  const page = await browser.newPage();

  // 拦截所有 OKKI API 响应
  page.on('response', async (response) => {
    const url = response.url();
    if (!url.includes('xiaoman') && !url.includes('okki') && !url.includes('alibaba')) return;

    try {
      const contentType = response.headers()['content-type'] || '';
      if (!contentType.includes('json')) return;

      const body = await response.json().catch(() => null);
      if (!body) return;

      captured.push({
        time: new Date().toISOString(),
        url: url,
        status: response.status(),
        data: body,
      });

      // 识别会话列表
      const list = body.data?.list || body.data?.records || body.list || body.records;
      const count = Array.isArray(list) ? list.length : (body.data?.total || body.total || 0);
      console.log(`  [API] ${response.status()} | ${count}条 | ${url.split('?')[0].split('/').slice(-2).join('/')}`);
    } catch (e) {
      // skip
    }
  });

  // 导航到 TM 页面
  console.log('[QuickSync] 导航到 TM 页面...');
  await page.goto('https://crm.xiaoman.cn/im/', { waitUntil: 'domcontentloaded', timeout: 30000 });

  // 等待页面加载 + API 响应
  console.log('[QuickSync] 等待 API 响应 (10秒)...');
  await page.waitForTimeout(10000);

  // 保存
  const timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
  const filepath = path.join(OUTPUT_DIR, `quicksync_${timestamp}.json`);

  fs.writeFileSync(filepath, JSON.stringify({
    syncedAt: new Date().toISOString(),
    apiCount: captured.length,
    responses: captured,
  }, null, 2));

  console.log(`[QuickSync] 完成。${captured.length} 个 API 响应 → ${filepath}`);

  await browser.close();
}

main().catch(err => {
  console.error('[QuickSync] 错误:', err.message);
  process.exit(1);
});

