/**
 * OKKI 快速同步 v2 — DOM + JS 提取会话元数据
 *
 * 使用：
 * 1. 关闭 Chrome
 * 2. node scripts/quick_sync.js
 */

const { chromium } = require('playwright');
const path = require('path');
const fs = require('fs');

const PROFILE_PATH = 'C:\\Users\\Administrator\\AppData\\Local\\Google\\Chrome\\User Data\\Profile 4';
const OUTPUT_DIR = path.join(__dirname, '..', 'data');

if (!fs.existsSync(OUTPUT_DIR)) {
  fs.mkdirSync(OUTPUT_DIR, { recursive: true });
}

const captured = [];
const wsMessages = [];

async function main() {
  console.log('[QuickSync v2] 启动 Chrome (Profile 4)...');

  const browser = await chromium.launchPersistentContext(PROFILE_PATH, {
    channel: 'chrome',
    headless: false,
    viewport: { width: 1440, height: 900 },
  });

  const page = await browser.newPage();

  // ---- HTTP 拦截 ----
  page.on('response', async (response) => {
    const url = response.url();
    if (!url.includes('xiaoman') && !url.includes('alibaba.com')) return;
    try {
      const ct = response.headers()['content-type'] || '';
      if (!ct.includes('json')) return;
      const body = await response.json().catch(() => null);
      if (!body) return;
      captured.push({ time: new Date().toISOString(), url, status: response.status(), data: body });
      console.log(`  [HTTP] ${response.status()} ${url.slice(0, 120)}`);
    } catch (e) {}
  });

  // ---- WebSocket 拦截 ----
  page.on('websocket', (ws) => {
    console.log(`  [WS] 连接: ${ws.url().slice(0, 100)}`);
    ws.on('framereceived', (frame) => {
      try {
        const text = frame.payload.toString('utf-8');
        if (text.length < 20) return;
        const obj = JSON.parse(text);
        wsMessages.push({ time: new Date().toISOString(), url: ws.url(), data: obj });
        console.log(`  [WS←] ${text.slice(0, 150)}`);
      } catch (e) {}
    });
  });

  // ---- 导航 ----
  console.log('[QuickSync v2] 导航到 TM 页面...');
  await page.goto('https://crm.xiaoman.cn/im/', { waitUntil: 'domcontentloaded', timeout: 30000 });
  const actualUrl = page.url();
  console.log(`[QuickSync v2] 实际 URL: ${actualUrl}`);

  // 等待更多时间让 WebSocket 连接和数据加载
  console.log('[QuickSync v2] 等待数据加载 (15秒)...');
  await page.waitForTimeout(15000);

  // ---- 尝试从 DOM 提取 ----
  const domData = await page.evaluate(() => {
    const result = { title: document.title, url: location.href, items: [] };

    // 尝试多种选择器找到会话列表项
    const selectors = [
      '[class*="conversation"]', '[class*="chat-item"]', '[class*="session"]',
      '[class*="contact-item"]', '[class*="list-item"]', '[class*="message-item"]',
      '[class*="im-item"]', '[class*="talk"]', 'li[class*="item"]',
      '[class*="CustomerList"]', '[class*="customer"]',
    ];

    for (const sel of selectors) {
      const els = document.querySelectorAll(sel);
      if (els.length > 0) {
        result.selector = sel;
        result.count = els.length;
        // 提取前 5 个的文本
        for (let i = 0; i < Math.min(els.length, 5); i++) {
          result.items.push(els[i].textContent.slice(0, 200));
        }
        break;
      }
    }

    // 尝试找 window 上的数据
    result.windowKeys = Object.keys(window).filter(k =>
      k.toLowerCase().includes('store') || k.toLowerCase().includes('state') ||
      k.toLowerCase().includes('sdk') || k.toLowerCase().includes('tm') ||
      k.toLowerCase().includes('im') || k.toLowerCase().includes('chat') ||
      k.toLowerCase().includes('conversation')
    ).slice(0, 15);

    // 尝试找 React/Vue 根组件
    const root = document.getElementById('root') || document.getElementById('app') || document.querySelector('[class*="app"]');
    result.hasRoot = !!root;

    return result;
  });

  console.log(`[QuickSync v2] DOM 分析:`);
  console.log(`  标题: ${domData.title}`);
  console.log(`  URL: ${domData.url}`);
  console.log(`  选择器匹配: ${domData.selector || '无'} (${domData.count || 0}个)`);
  console.log(`  window 关键 key: ${domData.windowKeys.join(', ') || '无'}`);

  // ---- 保存 ----
  const ts = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
  const filepath = path.join(OUTPUT_DIR, `quicksync_${ts}.json`);

  fs.writeFileSync(filepath, JSON.stringify({
    syncedAt: new Date().toISOString(),
    actualUrl,
    domData,
    httpCount: captured.length,
    wsCount: wsMessages.length,
    httpResponses: captured,
    wsMessages: wsMessages.slice(0, 20),
  }, null, 2));

  console.log(`[QuickSync v2] 完成。HTTP:${captured.length} WS:${wsMessages.length} → ${filepath}`);
  await browser.close();
}

main().catch(err => {
  console.error('[QuickSync v2] 错误:', err.message);
  process.exit(1);
});

