/**
 * OKKI 快速同步 v3 — 等待手动登录后自动抓取
 *
 * 使用：
 * 1. 关闭 Chrome
 * 2. node scripts/quick_sync.js
 * 3. 在浏览器中手动登录 OKKI
 * 4. 登录成功后自动抓取 → 保存 → 退出
 */

const { chromium } = require('playwright');
const path = require('path');
const fs = require('fs');

const PROFILE_PATH = 'C:\\Users\\Administrator\\AppData\\Local\\Google\\Chrome\\User Data\\Profile 4';
const OUTPUT_DIR = path.join(__dirname, '..', 'data');

if (!fs.existsSync(OUTPUT_DIR)) {
  fs.mkdirSync(OUTPUT_DIR, { recursive: true });
}

const captured = [];
const wsMessages = [];

async function main() {
  console.log('[QuickSync v3] 启动 Chrome (Profile 4)...');

  const browser = await chromium.launchPersistentContext(PROFILE_PATH, {
    channel: 'chrome',
    headless: false,
    viewport: { width: 1440, height: 900 },
  });

  const page = await browser.newPage();

  // ---- HTTP 拦截 ----
  page.on('response', async (response) => {
    const url = response.url();
    if (!url.includes('xiaoman') && !url.includes('alibaba.com')) return;
    try {
      const ct = response.headers()['content-type'] || '';
      if (!ct.includes('json')) return;
      const body = await response.json().catch(() => null);
      if (!body) return;
      captured.push({ time: new Date().toISOString(), url, status: response.status(), data: body });
      const short = url.split('?')[0];
      const list = body.data?.list || body.data?.records || body.list;
      const count = Array.isArray(list) ? list.length : (body.data?.total || body.total || '');
      console.log(`  [HTTP] ${response.status()} | ${count} | ${short.slice(-60)}`);
    } catch (e) {}
  });

  // ---- WebSocket 拦截 ----
  page.on('websocket', (ws) => {
    const wsUrl = ws.url();
    console.log(`  [WS] 连接: ${wsUrl.slice(0, 80)}`);
    ws.on('framereceived', (frame) => {
      try {
        const text = frame.payload.toString('utf-8');
        if (text.length < 20) return;
        const obj = JSON.parse(text);
        wsMessages.push({ time: new Date().toISOString(), url: wsUrl, data: obj });

        // 会话列表
        if (obj.body?.userMessageModels) {
          console.log(`  [WS←] 消息列表: ${obj.body.userMessageModels.length}条, nextCursor:${obj.body.nextCursor || 'none'}`);
        } else if (obj.code !== undefined) {
          console.log(`  [WS←] code=${obj.code} ${text.slice(0, 120)}`);
        }
      } catch (e) {}
    });
  });

  // ---- 导航到 OKKI ----
  console.log('[QuickSync v3] 导航到 OKKI...');
  await page.goto('https://crm.xiaoman.cn/im/', { waitUntil: 'domcontentloaded', timeout: 30000 });

  // ---- 等待用户登录 ----
  console.log('');
  console.log('========================================');
  console.log('  请在浏览器中手动登录 OKKI');
  console.log('  登录成功后脚本会自动检测并开始抓取');
  console.log('========================================');
  console.log('');

  // 等用户登录 (最多等 5 分钟)
  const startTime = Date.now();
  const maxWait = 5 * 60 * 1000;

  while (Date.now() - startTime < maxWait) {
    const currentUrl = page.url();

    // 检测是否已登录成功（URL 不再是 login 页面）
    if (!currentUrl.includes('login.xiaoman.cn') && currentUrl.includes('crm.xiaoman.cn')) {
      console.log('[QuickSync v3] 检测到已登录！开始等待数据加载...');
      break;
    }

    // 每 2 秒检查一次
    await page.waitForTimeout(2000);
  }

  if (page.url().includes('login.xiaoman.cn')) {
    console.log('[QuickSync v3] 超时：5分钟内未检测到登录成功。退出。');
    await browser.close();
    process.exit(1);
  }

  // ---- 登录后等待数据加载 ----
  // 给 WebSocket 连接和数据加载留时间
  await page.waitForTimeout(12000);

  // ---- DOM 提取 ----
  const domData = await page.evaluate(() => {
    const result = { title: document.title, url: location.href, items: [] };
    const selectors = [
      '[class*="conversation"]', '[class*="chat-item"]', '[class*="session"]',
      '[class*="contact-item"]', '[class*="list-item"]', '[class*="im-item"]',
      '[class*="CustomerList"]', '[class*="customer"]',
    ];
    for (const sel of selectors) {
      const els = document.querySelectorAll(sel);
      if (els.length > 3) {
        result.selector = sel;
        result.count = els.length;
        for (let i = 0; i < Math.min(els.length, 5); i++) {
          result.items.push(els[i].textContent?.slice(0, 200));
        }
        break;
      }
    }
    return result;
  });

  console.log(`[QuickSync v3] DOM: ${domData.selector || '无匹配'} (${domData.count || 0}个)`);

  // ---- 保存 ----
  const ts = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
  const filepath = path.join(OUTPUT_DIR, `quicksync_${ts}.json`);

  fs.writeFileSync(filepath, JSON.stringify({
    syncedAt: new Date().toISOString(),
    actualUrl: page.url(),
    domData,
    httpCount: captured.length,
    wsCount: wsMessages.length,
    httpResponses: captured,
    wsMessages: wsMessages.slice(0, 50),
  }, null, 2));

  console.log(`[QuickSync v3] 完成。HTTP:${captured.length} WS:${wsMessages.length} → ${filepath}`);
  await browser.close();
}

main().catch(err => {
  console.error('[QuickSync v3] 错误:', err.message);
  process.exit(1);
});

