1	// OKKI CRM 全量聊天历史抓取
2	// 通过 CDP 注入 JS，劫持 WebSocket 发 LWP 协议拉取
3	// 用法: node scripts/lwp_scrape_all.js
4	// 前提: Chrome 已启动 --remote-debugging-port=9222，TM 页面已打开
5	
6	const { chromium } = require('playwright');
7	const fs = require('fs');
8	const path = require('path');
9	
10	const DATA_DIR = path.join(__dirname, '..', 'data', 'chat_history');
11	const BATCH_SIZE = 20;   // 每批并发数（LWP 走同一个 WS，不能太快）
12	const MSG_COUNT = 50;    // 每次拉取条数
13	const MAX_PAGES = 20;    // 单个会话最大翻页数
14	const BATCH_DELAY = 500;  // 批次间延迟 ms
15	
16	// ========== 工具函数 ==========
17	
18	function ts() { return new Date().toISOString().replace(/[:.]/g, '-'); }
19	
20	function log(msg) { console.log(`[${new Date().toLocaleTimeString()}] ${msg}`); }
21	
22	// ========== 主流程 ==========
23	
24	(async () => {
25	  log('连接 CDP...');
26	  const browser = await chromium.connectOverCDP('http://localhost:9222');
27	  const pages = browser.contexts()[0].pages();
28	  const page = pages[0];
29	  const client = await page.context().newCDPSession(page);
30	
31	  // 找到 onetalk iframe
32	  const targets = await client.send('Target.getTargets');
33	  const ot = targets.targetInfos.find(t => t.url.includes('onetalk') && t.type === 'iframe');
34	  if (!ot) { log('错误: 未找到 onetalk iframe，TM 页面是否已打开？'); process.exit(1); }
35	  log('onetalk iframe 已找到');
36	
37	  const { sessionId } = await client.send('Target.attachToTarget', { targetId: ot.targetId, flatten: false });
38	
39	  // 响应收集
40	  let evalResults = {};
41	  let consoleMsgs = [];
42	
43	  client.on('Target.receivedMessageFromTarget', (msg) => {
44	    if (msg.sessionId !== sessionId) return;
45	    try {
46	      const m = JSON.parse(msg.message);
47	      if (m.id && m.result) {
48	        const val = m.result.result ? m.result.result.value : null;
49	        if (val !== null && val !== undefined) {
50	          try { evalResults[m.id] = JSON.parse(val); } catch (e) { evalResults[m.id] = val; }
51	        } else {
52	          evalResults[m.id] = m.result;
53	        }
54	      }
55	      if (m.method === 'Runtime.consoleAPICalled') {
56	        const text = (m.params.args || []).map(a => a.value || a.description || '').join(' ');
57	        if (text.startsWith('[LWP')) consoleMsgs.push(text);
58	      }
59	    } catch (e) {}
60	  });
61	
62	  await client.send('Target.sendMessageToTarget', {
63	    sessionId,
64	    message: JSON.stringify({ id: 0, method: 'Runtime.enable', params: {} })
65	  });
66	
67	  // ========== Step 1: 检查并确保 SDK 已连接 ==========
68	  log('检查 SDK 状态...');
69	  await evaluate(sessionId, client, 1, `
70	    (function(){var a=window._imBaaSSDK.getAuthService();return JSON.stringify({isLogin:a.isLogin(),status:a.connectionStatus,uid:a.getLoginUid()})})()
71	  `);
