85	  // ========== Step 2: 劫持 WebSocket 并安装 LWP 收发器 ==========
86	  // 策略：
87	  //   1. 保存原始 send / addEventListener
88	  //   2. 劫持 send → 捕获 WS 实例
89	  //   3. 捕获后，用原始 addEventListener 给自己的 handler 订阅 message
90	  //   4. 收到响应按 mid 匹配 promise，事件驱动，无需轮询
91	  log('安装 LWP 收发器...');
92	  await evaluate(sessionId, client, 3, `
93	    (function() {
94	      var _send = WebSocket.prototype.send;
95	      var _ae = WebSocket.prototype.addEventListener;
96	      var _rem = WebSocket.prototype.removeEventListener;
97	
98	      window.__lwpPending = {};
99	      window.__lwpSeq = 0;
100	
101	      // 劫持 send → 第一次 send 时捕获 WS 并安装响应监听
102	      WebSocket.prototype.send = function(data) {
103	        if (!window.__lwpWs && this.readyState === 1) {
104	          window.__lwpWs = this;
105	          // 用原始 addEventListener 给自己的 handler 订阅（不经过劫持）
106	          _ae.call(this, 'message', function(event) {
107	            try {
108	              var raw = typeof event.data === 'string' ? event.data : '';
109	              if (raw.indexOf('"code"') < 0) return; // 不是 LWP 响应
110	              var parsed = JSON.parse(raw);
111	              var mid = parsed.headers && parsed.headers.mid;
112	              if (mid && window.__lwpPending[mid]) {
113	                var p = window.__lwpPending[mid];
114	                delete window.__lwpPending[mid];
115	                p.resolve(parsed);
116	              }
117	            } catch(e) {}
118	          });
119	          console.log('[LWP] WS captured: ' + this.url);
120	        }
121	        return _send.call(this, data);
122	      };
123	
124	      // 发 LWP 请求，返回 Promise<response>
125	      window.__lwpRequest = function(lwpPath, body) {
126	        return new Promise(function(resolve, reject) {
127	          var ws = window.__lwpWs;
128	          if (!ws || ws.readyState !== 1) { reject(new Error('WS not ready')); return; }
129	          var mid = Date.now() + ' ' + (++window.__lwpSeq);
