    const maxWait = 5 * 60 * 1000;
    while (Date.now() - startTime < maxWait) {
      const url = page.url();
      if (!url.includes('login.xiaoman.cn') && !url.includes('login.alibaba.com') && url.includes('crm.xiaoman.cn')) {
        log('登录成功！');
        break;
      }
      await sleep(2000);
    }
    if (page.url().includes('login')) {
      log('超时：未检测到登录。退出。');
      await browser.close();
      process.exit(1);
    }
  } else {
