const fs = require('fs');
const path = require('path');

const CHAT_DIR = 'data/chat_history';
const CUTOFF = new Date('2026-05-05T14:00:00Z').getTime(); // After May 5 scrape

// Get the 21 changed CIDs from the sync output
// Actually let me just check all chat files for messages after cutoff
const files = fs.readdirSync(CHAT_DIR).filter(f => f.endsWith('.json') && f !== '_summary.json');

let totalReceived = 0;       // 客户发来的消息
let totalSent = 0;           // 我方发出的消息
let customersReplied = new Set();  // 有回复的客户CID
let receivedSamples = [];    // 收集样本

for (const file of files) {
  try {
    const data = JSON.parse(fs.readFileSync(path.join(CHAT_DIR, file), 'utf-8'));
    const msgs = data.messages || [];

    for (const msg of msgs) {
      // gmtChat is the timestamp, messageType indicates direction
      const ts = msg.gmtChat || msg.gmtCreate || 0;
      if (ts < CUTOFF) continue;  // Before May 5 evening, skip

      if (msg.messageType === 'received') {
        totalReceived++;
        customersReplied.add(data.cid);
        if (receivedSamples.length < 20) {
          receivedSamples.push({
            customer: data.name,
            cid: data.cid,
            time: new Date(ts).toISOString(),
            content: (msg.content || '').slice(0, 80),
            from: msg.fromUserName || msg.fromUserId || ''
          });
        }
      } else if (msg.messageType === 'send') {
        totalSent++;
      }
    }
  } catch(e) {}
}

console.log('5/5晚之后的消息统计:');
console.log('客户回复消息数:', totalReceived);
console.log('我方发送消息数:', totalSent);
console.log('有回复的客户数:', customersReplied.size);
console.log('');
console.log('=== 客户回复样本 ===');
receivedSamples.sort((a,b) => a.time.localeCompare(b.time));
for (const s of receivedSamples) {
  console.log(s.time.slice(0,16) + ' | ' + (s.customer || '?') + ' | ' + s.content);
}
"

