// Check a few changed conversations
const cids = [
  '1507582644648-2500000853693#11011@icbu', // ali Amjid - had 234 msgs
  '2034017314980-2500000853693#11011@icbu', // Changed
];

for (const cid of cids.slice(0,2)) {
  const fp = path.join(CHAT_DIR, sanitize(cid) + '.json');
  if (!fs.existsSync(fp)) { console.log(cid + ': FILE NOT FOUND'); continue; }
  const data = JSON.parse(fs.readFileSync(fp, 'utf-8'));
  console.log('=== ' + data.name + ' (' + data.totalMessages + ' msgs) ===');

  // Look at ALL fields across all messages to understand structure
  const allKeys = new Set();
  for (const m of (data.messages || []).slice(0, 50)) {
    Object.keys(m).forEach(k => allKeys.add(k));
  }
  console.log('Top-level keys:', [...allKeys].join(', '));

  // Check if there's any field with messageType/direction info at top level
  const sample = data.messages?.[0];
  if (sample) {
    console.log('Sample msg readStatus:', sample.readStatus);
    console.log('Sample has readStatus type:', typeof sample.readStatus);
  }

  // Try to decode basicMessageInfo
  const lastMsgs = (data.messages || []).slice(-5);
  for (const m of lastMsgs) {
    try {
      const bmi = m.message?.extension?.basicMessageInfo;
      if (bmi) {
        const decoded = JSON.parse(bmi);
        console.log('decoded bmi:', JSON.stringify(decoded).slice(0, 200));
      }
    } catch(e) {}
  }

  // Check for any message that has content at the message level
  let contentMsgs = 0;
  for (const m of (data.messages || [])) {
    if (m.content) contentMsgs++;
  }
  console.log('Messages with top-level content:', contentMsgs + '/' + (data.messages||[]).length);
  console.log('');
}
