const fs = require('fs');

// Compare old and new data to see what changed
const old = JSON.parse(fs.readFileSync('data/tm_conversations_full.json', 'utf-8'));
const latest = JSON.parse(fs.readFileSync('data/tm_conversations_latest.json', 'utf-8'));

