// Find conversations where LAST CONTACT TIME changed (regardless of direction)
const lctChanged = [];
for (const c of latest.conversations) {
  const oldC = oldMap.get(c.cid);
  if (!oldC) { lctChanged.push({name:c.name, oldLct:0, newLct:c.lastContactTime, reason:'new'}); continue; }
  if ((c.lastContactTime || 0) > (oldC.lastContactTime || 0)) {
    lctChanged.push({name:c.name, oldLct:oldC.lastContactTime, newLct:c.lastContactTime, reason:'updated'});
  }
}

