for (const c of lctChanged.slice(0, 25)) {
  const newDate = new Date(c.newLct).toISOString().slice(0,16);
  const oldDate = c.oldLct ? new Date(c.oldLct).toISOString().slice(0,16) : 'NEW';
  console.log(newDate + ' (was ' + oldDate + ') | ' + c.reason + ' | ' + c.name);
}

