cd "d:/ClaudeWorkspace/08_客户跟进/Okki" && node -e "
const fs = require('fs');
const path = require('path');
const CHAT_DIR = 'data/chat_history';
const CUTOFF = new Date('2026-05-05T14:00:00Z').getTime(); // After last scrape

const OUR_UID = '2500000853693@icbu';
const files = fs.readdirSync(CHAT_DIR).filter(f => f.endsWith('.json') && f !== '_summary.json');

let totalCustomerMsgs = 0;    // 客户发的消息
let totalOurMsgs = 0;         // 我方发的消息
let totalSystemMsgs = 0;      // 系统/自动回复
let customersWithReplies = new Map(); // cid → {name, count, latestTime, sample}

for (const file of files) {
  const data = JSON.parse(fs.readFileSync(path.join(CHAT_DIR, file), 'utf-8'));
  const msgs = data.messages || [];
  let customerCount = 0;
  let latestCustomerTime = 0;
  let sampleContent = '';

  for (const msg of msgs) {
    const ts = msg.message?.createAt || 0;
    if (ts < CUTOFF) continue;  // 只看5/5之后

    const senderUid = msg.message?.sender?.uid || '';
    const content = msg.message?.content?.text?.content || '';
    const bmi = msg.message?.extension?.basicMessageInfo || '{}';
    let isSystem = false;
    try { const info = JSON.parse(bmi); isSystem = info.systemMessage || info.autoReply; } catch(e) {}

    if (isSystem) {
      totalSystemMsgs++;
      continue;
    }

    if (senderUid === OUR_UID) {
      totalOurMsgs++;
    } else if (senderUid && content) {
      totalCustomerMsgs++;
      customerCount++;
      if (ts > latestCustomerTime) {
        latestCustomerTime = ts;
        sampleContent = content;
      }
    }
  }

  if (customerCount > 0) {
    customersWithReplies.set(data.cid, {
      name: data.name,
      count: customerCount,
      latestTime: latestCustomerTime,
      sample: sampleContent
    });
  }
}

console.log('=== 5/5晚之后消息统计 ===');
console.log('我方发送: ' + totalOurMsgs);
console.log('客户回复: ' + totalCustomerMsgs);
console.log('系统消息: ' + totalSystemMsgs);
console.log('有回复的客户数: ' + customersWithReplies.size);
console.log('');

// Sort by latest reply time
const sorted = [...customersWithReplies.values()].sort((a,b) => b.latestTime - a.latestTime);
console.log('=== 客户回复列表 (按时间倒序) ===');
for (const c of sorted) {
  const ts = new Date(c.latestTime).toISOString().slice(0,16);
  console.log(ts + ' | ' + c.name + ' | ' + c.count + '条回复 | ' + c.sample.slice(0, 80));
}
"

